WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/35.0/connection.js")}
{!REQUIRESCRIPT("/soap/ajax/35.0/apex.js")}

if ({!NOT( ISNULL(Contact.Mogli_SMS__Mogli_Number__c) )}){

var url;
if('{!$Label.mogli_sms__namespace}' === "none"){
url="/apex/" + "SendSMS?ids={!Contact.Id}"; 
} else { 
url="/apex/" + '{!$Label.mogli_sms__namespace}' + "SendSMS?ids={!Contact.Id}"; 
}

window.open(url, 'Popup','height=510,width=1200,top=0,left=0,location=no,menubar=no,titlebar=no,toolbar=no,status=no');
}
else{
alert ("Mogli Number Missing.");
}
